import { getAllProducts, getCatalogRefreshedAt, syncLatestCatalog } from '../lib/db';

async function syncCatalogAction() {
  'use server';

  await syncLatestCatalog();
  revalidateTag('products');
}

export default async function Page() {
  const products = await getAllProducts();
  const refreshedAt = getCatalogRefreshedAt();

  return (
    <main style={{ padding: 24, fontFamily: 'system-ui, sans-serif' }}>
      <section style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', gap: 16 }}>
        <div>
          <h1 style={{ margin: 0 }}>Product Catalog</h1>
