            Fast read-heavy browsing with background sync for eventual consistency.
          </p>
          <p style={{ marginTop: 4, color: '#777', fontSize: 14 }}>
            {refreshedAt ? `Last refreshed: ${refreshedAt.toLocaleString()}` : 'Catalog has not been refreshed yet.'}
          </p>
        </div>

        <form action={syncCatalogAction}>
          <button
            type="submit"
            style={{
              padding: '10px 16px',
              borderRadius: 8,
              border: '1px solid #111',
              background: '#111',
              color: '#fff',
              cursor: 'pointer',
            }}
          >
            Sync latest catalog
          </button>
        </form>
      </section>

      <div style={{ marginTop: 24, border: '1px solid #e5e5e5', borderRadius: 12, overflow: 'hidden' }}>
        <table style={{ width: '100%', borderCollapse: 'collapse' }}>
          <thead style={{ background: '#fafafa' }}>
            <tr>
              <th style={th}>SKU</th>
              <th style={th}>Name</th>
              <th style={th}>Price</th>
              <th style={th}>Inventory</th>
              <th style={th}>Availability</th>
